 1вҶ’import Foundation
 2вҶ’
 3вҶ’/// Monitors system memory pressure and invokes callbacks.
 4вҶ’/// Used as safety net for extreme memory situations.
 5вҶ’@MainActor
 6вҶ’final class MemoryPressureMonitor {
 7вҶ’    enum PressureLevel: Equatable {
 8вҶ’        case warning, critical
 9вҶ’    }
10вҶ’
11вҶ’    var onPressure: ((PressureLevel) -> Void)?
12вҶ’
13вҶ’    private var source: (any DispatchSourceMemoryPressure)?
14вҶ’
15вҶ’    func start() {
16вҶ’        guard source == nil else { return }  // Idempotent вҖ” avoid leaking duplicate sources
17вҶ’        let source = DispatchSource.makeMemoryPressureSource(eventMask: [.warning, .critical], queue: .main)
18вҶ’        source.setEventHandler { [weak self] in
19вҶ’            guard let self else { return }
20вҶ’            let event = source.data
21вҶ’            if event.contains(.critical) {
22вҶ’                self.onPressure?(.critical)
23вҶ’            } else if event.contains(.warning) {
24вҶ’                self.onPressure?(.warning)
25вҶ’            }
26вҶ’        }
27вҶ’        source.resume()
28вҶ’        self.source = source
29вҶ’    }
30вҶ’
31вҶ’    func stop() {
32вҶ’        source?.cancel()
33вҶ’        source = nil
34вҶ’    }
35вҶ’
36вҶ’    /// Test-only: simulate a pressure event.
37вҶ’    func _testSimulatePressure(_ level: PressureLevel) {
38вҶ’        onPressure?(level)
39вҶ’    }
40вҶ’}
41вҶ’

200вҶ’    /// иЁҲз®— fit-to-width зё®ж”ҫеҫҢзҡ„й«ҳеәҰпјҲйҳІжӯўйҷӨд»Ҙйӣ¶пјү
201вҶ’    private func scaledHeightForSize(_ size: NSSize) -> CGFloat {
202вҶ’        guard size.width > 0 else {
203вҶ’            return containerWidth / defaultAspectRatio
204вҶ’        }
205вҶ’        return (size.height / size.width) * containerWidth
